  .module-card .icon {
    font-size: 1.5rem;
    margin-bottom: 0.5rem;
    display: block;
  }

  .module-card strong {
    display: block;
    font-size: 0.95rem;
    font-weight: 600;
    color: #1e293b;
    margin-bottom: 0.2rem;
  }

  .module-card span {
    font-size: 0.82rem;
    color: #64748b;
    font-family: 'IBM Plex Mono', monospace;
  }

  .guide-section {
    margin: 2.5rem 0;
  }

