    font-size: 1.35rem;
    font-weight: 600;
    color: #1e293b;
    margin-bottom: 0.25rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid #e2e8f0;
  }

  .guide-section .subtitle {
    color: #64748b;
    font-size: 0.92rem;
    margin: 0 0 1.25rem;
  }

  .step {
